 pub struct AgentListEntry {
     pub id: AgentId,
     pub feature: String,
     pub ready: bool,
     pub hidden: bool,
     pub modified_files: Vec<PathBuf>,
     pub conflicting_agents: Vec<AgentId>,
     pub depends_on: Vec<AgentId>,
