         let layout = self.layout();
         let inner_width = layout.right_width.saturating_sub(2).max(1);
         let body_height = self.height.saturating_sub(1);
         let inner_height = body_height.saturating_sub(2).max(1);
         (inner_width, inner_height)
     }

